    #[test]
    fn dataframe_filter_rows_basic() {
        let df = DataFrame::from_dict(
            &["a", "b"],
            vec![
                (
                    "a",
                    vec![Scalar::Int64(1), Scalar::Int64(2), Scalar::Int64(3)],
                ),
                (
                    "b",
                    vec![Scalar::Int64(10), Scalar::Int64(20), Scalar::Int64(30)],
                ),
            ],
        )
        .unwrap();

        let mask = Series::from_values(
            "mask",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![Scalar::Bool(true), Scalar::Bool(false), Scalar::Bool(true)],
        )
        .unwrap();

        let result = df.filter_rows(&mask).unwrap();
        assert_eq!(result.len(), 2);
        assert_eq!(
            result.column("a").unwrap().values(),
            &[Scalar::Int64(1), Scalar::Int64(3)]
        );
        assert_eq!(
            result.column("b").unwrap().values(),
            &[Scalar::Int64(10), Scalar::Int64(30)]
        );
    }

    #[test]
    fn dataframe_filter_rows_ignores_extra_mask_labels() {
        let df = DataFrame::from_dict(
            &["a"],
            vec![("a", vec![Scalar::Int64(1), Scalar::Int64(2)])],
        )
        .unwrap();

        let mask = Series::from_values(
            "mask",
            vec![IndexLabel::from(0_i64), IndexLabel::from(2_i64)],
            vec![Scalar::Bool(true), Scalar::Bool(true)],
        )
        .unwrap();

        let result = df.filter_rows(&mask).unwrap();
        assert_eq!(result.len(), 1);
        assert_eq!(result.index().labels(), &[IndexLabel::from(0_i64)]);
        assert_eq!(result.column("a").unwrap().values(), &[Scalar::Int64(1)]);
    }

    #[test]
    fn dataframe_filter_rows_rejects_non_boolean_mask() {
        let df = DataFrame::from_dict(
            &["a", "b"],
            vec![
                (
                    "a",
                    vec![Scalar::Int64(1), Scalar::Int64(2), Scalar::Int64(3)],
                ),
                (
                    "b",
                    vec![Scalar::Int64(10), Scalar::Int64(20), Scalar::Int64(30)],
                ),
            ],
        )
        .unwrap();

        let mask = Series::from_values(
            "mask",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![Scalar::Int64(1), Scalar::Int64(0), Scalar::Int64(1)],
        )
        .unwrap();

        let err = df.filter_rows(&mask).unwrap_err();
        assert!(
            matches!(err, FrameError::CompatibilityRejected(msg) if msg.contains("boolean mask required for filter_rows"))
        );
    }

    #[test]
    fn dataframe_filter_rows_duplicate_index_uses_first_occurrence() {
        let index = Index::new(vec![
            IndexLabel::from("a"),
            IndexLabel::from("a"),
            IndexLabel::from("b"),
        ]);
        let mut columns = BTreeMap::new();
        columns.insert(
            "x".to_string(),
            Column::from_values(vec![Scalar::Int64(1), Scalar::Int64(2), Scalar::Int64(3)])
                .unwrap(),
        );
        columns.insert(
            "y".to_string(),
            Column::from_values(vec![
                Scalar::Int64(10),
                Scalar::Int64(20),
                Scalar::Int64(30),
            ])
            .unwrap(),
        );
        let df = DataFrame::new_with_column_order(
            index,
            columns,
            vec!["x".to_string(), "y".to_string()],
        )
        .unwrap();

        let mask = Series::from_values(
            "mask",
            vec![IndexLabel::from("a"), IndexLabel::from("b")],
            vec![Scalar::Bool(true), Scalar::Bool(true)],
        )
        .unwrap();

        let result = df.filter_rows(&mask).unwrap();
        assert_eq!(
            result.index().labels(),
            &[
                IndexLabel::from("a"),
                IndexLabel::from("a"),
                IndexLabel::from("b")
            ]
        );
        assert_eq!(
            result.column("x").unwrap().values(),
            &[Scalar::Int64(1), Scalar::Int64(1), Scalar::Int64(3)]
        );
        assert_eq!(
            result.column("y").unwrap().values(),
            &[Scalar::Int64(10), Scalar::Int64(10), Scalar::Int64(30)]
        );
    }

    #[test]
