    #[test]
    fn dataframe_duplicated_keep_variants() {
        let df = DataFrame::from_dict(
            &["a", "b"],
            vec![
                (
                    "a",
                    vec![
                        Scalar::Int64(1),
                        Scalar::Int64(1),
                        Scalar::Int64(2),
                        Scalar::Int64(1),
                        Scalar::Int64(2),
                    ],
                ),
                (
                    "b",
                    vec![
                        Scalar::Utf8("x".to_owned()),
                        Scalar::Utf8("x".to_owned()),
                        Scalar::Utf8("y".to_owned()),
                        Scalar::Utf8("x".to_owned()),
                        Scalar::Utf8("z".to_owned()),
                    ],
                ),
            ],
        )
        .unwrap();

        let first = df.duplicated(None, DuplicateKeep::First).unwrap();
        assert_eq!(
            first.values(),
            &[
                Scalar::Bool(false),
                Scalar::Bool(true),
                Scalar::Bool(false),
                Scalar::Bool(true),
                Scalar::Bool(false)
            ]
        );

        let last = df.duplicated(None, DuplicateKeep::Last).unwrap();
        assert_eq!(
            last.values(),
            &[
                Scalar::Bool(true),
                Scalar::Bool(true),
                Scalar::Bool(false),
                Scalar::Bool(false),
                Scalar::Bool(false)
            ]
        );

        let none = df.duplicated(None, DuplicateKeep::None).unwrap();
        assert_eq!(
            none.values(),
            &[
                Scalar::Bool(true),
                Scalar::Bool(true),
                Scalar::Bool(false),
                Scalar::Bool(true),
                Scalar::Bool(false)
            ]
        );
    }

