    #[test]
    fn dataframe_pct_change() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "a",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
                vec![
                    Scalar::Float64(100.0),
                    Scalar::Float64(110.0),
                    Scalar::Float64(99.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();
        let result = df.pct_change(1).unwrap();
        let col = result.column("a").unwrap();
        assert!(col.values()[0].is_missing());
        if let Scalar::Float64(v) = &col.values()[1] {
            assert!((v - 0.1).abs() < 1e-10);
        }
    }

    #[test]
    fn dataframe_pct_change_axis1() {
        let df = DataFrame::from_dict(
            &["a", "b"],
            vec![
                ("a", vec![Scalar::Float64(100.0), Scalar::Float64(50.0)]),
                ("b", vec![Scalar::Float64(110.0), Scalar::Float64(40.0)]),
            ],
        )
        .unwrap();
        let result = df.pct_change_axis1(1).unwrap();
        let cola = result.column("a").unwrap();
        let colb = result.column("b").unwrap();
        assert!(cola.values()[0].is_missing());
        assert!(cola.values()[1].is_missing());

        assert!(matches!(&colb.values()[0], Scalar::Float64(_)));
        let Scalar::Float64(v0) = &colb.values()[0] else {
            return;
        };
        assert!((v0 - 0.1).abs() < 1e-10); // (110 - 100) / 100

        assert!(matches!(&colb.values()[1], Scalar::Float64(_)));
        let Scalar::Float64(v1) = &colb.values()[1] else {
            return;
        };
        assert!((v1 + 0.2).abs() < 1e-10); // (40 - 50) / 50
    }

