    #[test]
    fn series_autocorr_lag1() {
        // Perfectly correlated with lag 1: [1,2,3,4,5]
        let s = Series::from_values(
            "x",
            vec![
                0_i64.into(),
                1_i64.into(),
                2_i64.into(),
                3_i64.into(),
                4_i64.into(),
            ],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
                Scalar::Float64(4.0),
                Scalar::Float64(5.0),
            ],
        )
        .unwrap();

        let r = s.autocorr(1).unwrap();
        assert!((r - 1.0).abs() < 0.01);
    }

