    // ── GroupBy pct_change tests ──

    #[test]
    fn groupby_pct_change() {
        let df = DataFrame::from_dict(
            &["g", "v"],
            vec![
                (
                    "g",
                    vec![
                        Scalar::Utf8("a".to_owned()),
                        Scalar::Utf8("a".to_owned()),
                        Scalar::Utf8("a".to_owned()),
                    ],
                ),
                (
                    "v",
                    vec![
                        Scalar::Float64(100.0),
                        Scalar::Float64(110.0),
                        Scalar::Float64(121.0),
                    ],
                ),
            ],
        )
        .unwrap();

        let result = df.groupby(&["g"]).unwrap().pct_change(1).unwrap();
        let v = result.column_as_series("v").unwrap();
        assert!(v.values()[0].is_missing()); // first: NaN
        // (110-100)/100 = 0.1
        let f1 = expect_float64(&v.values()[1]);
        assert!((f1 - 0.1).abs() < 1e-10);
        // (121-110)/110 = 0.1
        let f2 = expect_float64(&v.values()[2]);
        assert!((f2 - 0.1).abs() < 1e-10);
    }

