    #[test]
    fn df_sem_agg() {
        let df = DataFrame::from_dict(
            &["x"],
            vec![(
                "x",
                vec![
                    Scalar::Float64(2.0),
                    Scalar::Float64(4.0),
                    Scalar::Float64(6.0),
                    Scalar::Float64(8.0),
                ],
            )],
        )
        .unwrap();
        let result = df.sem_agg().unwrap();
        // sem = std/sqrt(n) = 2.5819.../sqrt(4) ≈ 1.2909...
        let val = result.values()[0].to_f64().unwrap();
        assert!((val - 1.2909944).abs() < 0.001);
    }

