    // ── Series: rename, set_axis, truncate, combine ──

    #[test]
    fn series_rename() {
        let s = Series::from_values("old", vec![0_i64.into()], vec![Scalar::Int64(42)]).unwrap();
        let r = s.rename("new").unwrap();
        assert_eq!(r.name(), "new");
        assert_eq!(r.values()[0], Scalar::Int64(42));
    }

    #[test]
    fn series_set_axis() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into()],
            vec![Scalar::Int64(10), Scalar::Int64(20)],
        )
        .unwrap();
        let r = s.set_axis(vec!["a".into(), "b".into()]).unwrap();
        assert_eq!(r.index().labels(), &["a".into(), "b".into()]);
        assert_eq!(r.values()[0], Scalar::Int64(10));
    }

    #[test]
    fn series_truncate() {
        let s = Series::from_values(
            "x",
            vec![
                1_i64.into(),
                2_i64.into(),
                3_i64.into(),
                4_i64.into(),
                5_i64.into(),
            ],
            vec![
                Scalar::Int64(10),
                Scalar::Int64(20),
                Scalar::Int64(30),
                Scalar::Int64(40),
                Scalar::Int64(50),
            ],
        )
        .unwrap();
        let r = s
            .truncate(Some(&2_i64.into()), Some(&4_i64.into()))
            .unwrap();
        assert_eq!(r.len(), 3);
        assert_eq!(r.values()[0], Scalar::Int64(20));
        assert_eq!(r.values()[2], Scalar::Int64(40));
    }

    #[test]
    fn series_combine() {
        let a = Series::from_values(
            "x",
            vec![0_i64.into(), 2_i64.into()],
            vec![Scalar::Int64(10), Scalar::Int64(20)],
        )
        .unwrap();
        let b = Series::from_values(
            "y",
            vec![1_i64.into(), 2_i64.into()],
            vec![Scalar::Int64(5), Scalar::Int64(30)],
        )
        .unwrap();
        let result = a
            .combine(&b, |a_val, b_val| match (a_val.to_f64(), b_val.to_f64()) {
                (Ok(a), Ok(b)) => Scalar::Float64(a.max(b)),
                (Ok(a), Err(_)) => Scalar::Float64(a),
                (Err(_), Ok(b)) => Scalar::Float64(b),
                _ => Scalar::Null(NullKind::NaN),
            })
            .unwrap();
        assert_eq!(
            result.index().labels(),
            &vec![0_i64.into(), 2_i64.into(), 1_i64.into()]
        );
        assert_eq!(result.values()[0], Scalar::Float64(10.0));
        assert_eq!(result.values()[1], Scalar::Float64(30.0));
        assert_eq!(result.values()[2], Scalar::Float64(5.0));
    }

    // ── DataFrame: corrwith, dot ──

    #[test]
    fn df_corrwith() {
        let df1 = DataFrame::from_dict(
            &["x", "y"],
            vec![
                (
                    "x",
                    vec![
                        Scalar::Float64(1.0),
                        Scalar::Float64(2.0),
                        Scalar::Float64(3.0),
                    ],
                ),
                (
                    "y",
                    vec![
                        Scalar::Float64(4.0),
                        Scalar::Float64(5.0),
                        Scalar::Float64(6.0),
                    ],
                ),
            ],
        )
        .unwrap();
        let df2 = DataFrame::from_dict(
            &["x", "y"],
            vec![
                (
                    "x",
                    vec![
                        Scalar::Float64(1.0),
                        Scalar::Float64(2.0),
                        Scalar::Float64(3.0),
                    ],
                ),
                (
                    "y",
                    vec![
                        Scalar::Float64(6.0),
                        Scalar::Float64(5.0),
                        Scalar::Float64(4.0),
                    ],
                ),
            ],
        )
        .unwrap();
        let result = df1.corrwith(&df2).unwrap();
        // x correlates perfectly (1.0), y is perfectly anti-correlated (-1.0)
        let x_val = result.values()[0].to_f64().unwrap();
        let y_val = result.values()[1].to_f64().unwrap();
        assert!((x_val - 1.0).abs() < 0.001);
        assert!((y_val - (-1.0)).abs() < 0.001);
    }

    #[test]
    fn df_dot() {
        // [1 2]   [5 6]   [1*5+2*7  1*6+2*8]   [19 22]
        // [3 4] × [7 8] = [3*5+4*7  3*6+4*8] = [43 50]
        let a = DataFrame::from_dict_with_index(
            vec![
                ("c1", vec![Scalar::Float64(1.0), Scalar::Float64(3.0)]),
                ("c2", vec![Scalar::Float64(2.0), Scalar::Float64(4.0)]),
            ],
            vec![0_i64.into(), 1_i64.into()],
        )
        .unwrap();
        let b = DataFrame::from_dict_with_index(
            vec![
                ("d1", vec![Scalar::Float64(5.0), Scalar::Float64(7.0)]),
                ("d2", vec![Scalar::Float64(6.0), Scalar::Float64(8.0)]),
            ],
            vec![0_i64.into(), 1_i64.into()],
        )
        .unwrap();
        let result = a.dot(&b).unwrap();
        assert_eq!(result.shape(), (2, 2));
        assert_eq!(result.columns()["d1"].values()[0], Scalar::Float64(19.0));
        assert_eq!(result.columns()["d2"].values()[0], Scalar::Float64(22.0));
        assert_eq!(result.columns()["d1"].values()[1], Scalar::Float64(43.0));
        assert_eq!(result.columns()["d2"].values()[1], Scalar::Float64(50.0));
    }

    // ── Series to_csv / to_json ──

    #[test]
    fn series_to_csv() {
        let s = Series::from_values(
            "val",
            vec![0_i64.into(), 1_i64.into()],
            vec![Scalar::Int64(10), Scalar::Int64(20)],
        )
        .unwrap();
        let csv = s.to_csv(',', true);
        assert!(csv.contains(",val"));
        assert!(csv.contains("0,10"));
        assert!(csv.contains("1,20"));
    }

    #[test]
    fn series_to_csv_escapes_fields() {
        let s = Series::from_values(
            "name,with,comma",
            vec!["idx,1".into()],
            vec![Scalar::Utf8("val,1".to_owned())],
        )
        .unwrap();
        let csv = s.to_csv(',', true);
        assert!(csv.starts_with(",\"name,with,comma\"\n"));
        assert!(csv.contains("\"idx,1\",\"val,1\"\n"));
    }

    #[test]
    fn series_to_csv_escapes_carriage_returns() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into()],
            vec![Scalar::Utf8("line\rbreak".to_owned())],
        )
        .unwrap();
        let csv = s.to_csv(',', false);
        assert!(csv.contains("\"line\rbreak\""));
    }

    #[test]
    fn series_to_json_split() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into()],
            vec![Scalar::Int64(10), Scalar::Int64(20)],
        )
        .unwrap();
        let json = s.to_json("split").unwrap();
        assert!(json.contains("\"name\":\"x\""));
        assert!(json.contains("\"data\":[10,20]"));
    }

    #[test]
    fn series_to_json_index() {
        let s = Series::from_values(
            "x",
            vec!["a".into(), "b".into()],
            vec![Scalar::Int64(1), Scalar::Int64(2)],
        )
        .unwrap();
        let json = s.to_json("index").unwrap();
        assert!(json.contains("\"a\":1"));
        assert!(json.contains("\"b\":2"));
    }

    #[test]
    fn series_to_json_duplicate_index_rejected() {
        let s = Series::from_values(
            "x",
            vec!["dup".into(), "dup".into()],
            vec![Scalar::Int64(1), Scalar::Int64(2)],
        )
        .unwrap();
        let err = s
            .to_json("index")
            .expect_err("duplicate index labels should error");
        assert!(
            matches!(err, FrameError::CompatibilityRejected(msg) if msg.contains("duplicate index"))
        );
    }

    #[test]
    fn series_to_json_records() {
        let s = Series::from_values("x", vec![0_i64.into()], vec![Scalar::Float64(3.125)]).unwrap();
        let json = s.to_json("records").unwrap();
        assert!(json.contains("3.125"));
    }

    #[test]
    fn series_to_json_records_escapes_strings() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into()],
            vec![Scalar::Utf8("line\n\"quote\"".to_owned())],
        )
        .unwrap();
        let json = s.to_json("records").unwrap();
        let parsed: Value = serde_json::from_str(&json).unwrap();
        assert_eq!(parsed, serde_json::json!(["line\n\"quote\""]));
    }

    #[test]
    fn series_to_json_records_infinite_becomes_null() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into()],
            vec![Scalar::Float64(f64::INFINITY)],
        )
        .unwrap();
        let json = s.to_json("records").unwrap();
        let parsed: Value = serde_json::from_str(&json).unwrap();
        assert_eq!(parsed, serde_json::json!([null]));
    }

