    #[test]
    fn str_extractall_uses_named_group_as_column_name() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into()],
            vec![Scalar::Utf8("a1 b2".to_string())],
        )
        .unwrap();
        let result = s.str().extractall(r"(?P<digit>\d)").unwrap();
        let names: Vec<&str> = result.column_names().into_iter().map(String::as_str).collect();
        assert_eq!(names, vec!["digit"]);
        assert_eq!(
            result.column("digit").unwrap().values()[0],
            Scalar::Utf8("1".into())
        );
        assert_eq!(
            result.column("digit").unwrap().values()[1],
            Scalar::Utf8("2".into())
        );
    }

    #[test]
    fn str_extractall_mixes_named_and_positional_groups() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into()],
            vec![Scalar::Utf8("a1".to_string())],
        )
        .unwrap();
        let result = s.str().extractall(r"(?P<letter>[a-z])(\d)").unwrap();
        let names: Vec<&str> = result.column_names().into_iter().map(String::as_str).collect();
        assert_eq!(names, vec!["letter", "1"]);
    }

    #[test]
    fn str_extractall_positional_only_unchanged() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into()],
            vec![Scalar::Utf8("a1b2".to_string())],
        )
        .unwrap();
        let result = s.str().extractall(r"([a-z])(\d)").unwrap();
        let names: Vec<&str> = result.column_names().into_iter().map(String::as_str).collect();
        assert_eq!(names, vec!["0", "1"]);
    }

    // ── str.split_expand() ──

    #[test]
    fn str_split_expand_basic() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Utf8("a_b_c".to_string()),
                Scalar::Utf8("d_e".to_string()),
                Scalar::Utf8("f".to_string()),
            ],
        )
        .unwrap();
        let result = s.str().split_expand("_").unwrap();
        assert_eq!(result.column_names().len(), 3); // max parts = 3
        assert_eq!(
            result.columns["0"].values()[0],
            Scalar::Utf8("a".to_string())
        );
        assert_eq!(
            result.columns["1"].values()[0],
            Scalar::Utf8("b".to_string())
        );
        assert_eq!(
            result.columns["2"].values()[0],
            Scalar::Utf8("c".to_string())
        );
        // "d_e" only splits to 2, third col is NaN
        assert_eq!(
            result.columns["0"].values()[1],
            Scalar::Utf8("d".to_string())
        );
        assert_eq!(
            result.columns["1"].values()[1],
            Scalar::Utf8("e".to_string())
        );
        assert!(result.columns["2"].values()[1].is_missing());
        // "f" splits to 1
        assert_eq!(
            result.columns["0"].values()[2],
            Scalar::Utf8("f".to_string())
        );
        assert!(result.columns["1"].values()[2].is_missing());
    }

    // ── Rolling.corr / Rolling.cov ──

    #[test]
    fn rolling_corr_basic() {
        let a = Series::from_values(
            "a",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
                Scalar::Float64(4.0),
            ],
        )
        .unwrap();
        let b = Series::from_values(
            "b",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(2.0),
                Scalar::Float64(4.0),
                Scalar::Float64(6.0),
                Scalar::Float64(8.0),
            ],
        )
        .unwrap();
        let result = a.rolling(3, None).corr(&b).unwrap();
        // First two values should be NaN (window not full)
        assert!(result.values()[0].is_missing());
        assert!(result.values()[1].is_missing());
        // Perfect positive correlation
        let v = result.values()[2].to_f64().unwrap();
        assert!((v - 1.0).abs() < 1e-10);
    }

    #[test]
    fn rolling_cov_basic() {
        let a = Series::from_values(
            "a",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
            ],
        )
        .unwrap();
        let b = Series::from_values(
            "b",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(10.0),
                Scalar::Float64(20.0),
                Scalar::Float64(30.0),
            ],
        )
        .unwrap();
        let result = a.rolling(3, None).cov(&b).unwrap();
        assert!(result.values()[0].is_missing());
        assert!(result.values()[1].is_missing());
        // cov([1,2,3],[10,20,30]) = 10.0
        let v = result.values()[2].to_f64().unwrap();
        assert!((v - 10.0).abs() < 1e-10);
    }

