    #[test]
    fn test_series_fillna_limit() {
        let s = Series::from_values(
            "data",
            vec![
                0_i64.into(),
                1_i64.into(),
                2_i64.into(),
                3_i64.into(),
                4_i64.into(),
            ],
            vec![
                Scalar::Float64(1.0),
                Scalar::Null(NullKind::NaN),
                Scalar::Null(NullKind::NaN),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(5.0),
            ],
        )
        .unwrap();
        let result = s.fillna_limit(&Scalar::Float64(0.0), 2).unwrap();
        assert_eq!(result.column().values()[0], Scalar::Float64(1.0));
        assert_eq!(result.column().values()[1], Scalar::Float64(0.0)); // filled
        assert_eq!(result.column().values()[2], Scalar::Float64(0.0)); // filled
        assert!(result.column().values()[3].is_missing()); // limit exceeded
        assert_eq!(result.column().values()[4], Scalar::Float64(5.0));
    }

    #[test]
    fn test_series_fillna_limit_matches_fillna_on_null_dtype() {
        let s = Series::from_values(
            "data",
            vec![0_i64.into()],
            vec![Scalar::Null(NullKind::Null)],
        )
        .unwrap();
        let limited = s.fillna_limit(&Scalar::Int64(0), s.len()).unwrap();
        let unbounded = s.fillna(&Scalar::Int64(0)).unwrap();
        assert_eq!(limited.column().values(), &[Scalar::Int64(0)]);
        assert_eq!(unbounded.column().values(), &[Scalar::Int64(0)]);
        assert_eq!(limited, unbounded);
    }

