    #[test]
    fn series_first_offset_days() {
        let s = Series::from_values(
            "x",
            vec![
                "2024-01-01".into(),
                "2024-01-03".into(),
                "2024-01-05".into(),
                "2024-01-10".into(),
            ],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
                Scalar::Float64(4.0),
            ],
        )
        .unwrap();
        let result = s.first_offset("3D").unwrap();
        // 2024-01-01 + 3D = 2024-01-04, so include 01-01 and 01-03
        assert_eq!(result.len(), 2);
    }

