    // ── agg_named tests ──

    #[test]
    fn groupby_agg_named_basic() {
        let df = DataFrame::from_dict(
            &["region", "revenue", "qty"],
            vec![
                (
                    "region",
                    vec![
                        Scalar::Utf8("east".into()),
                        Scalar::Utf8("west".into()),
                        Scalar::Utf8("east".into()),
                        Scalar::Utf8("west".into()),
                    ],
                ),
                (
                    "revenue",
                    vec![
                        Scalar::Float64(100.0),
                        Scalar::Float64(200.0),
                        Scalar::Float64(150.0),
                        Scalar::Float64(250.0),
                    ],
                ),
                (
                    "qty",
                    vec![
                        Scalar::Int64(10),
                        Scalar::Int64(20),
                        Scalar::Int64(15),
                        Scalar::Int64(25),
                    ],
                ),
            ],
        )
        .unwrap();

        let result = df
            .groupby(&["region"])
            .unwrap()
            .agg_named(&[
                ("total_revenue", "revenue", "sum"),
                ("avg_qty", "qty", "mean"),
            ])
            .unwrap();

        assert_eq!(result.index().len(), 2);
        // Output columns should be named by the output_name, not input_col.
        assert!(result.column("total_revenue").is_some());
        assert!(result.column("avg_qty").is_some());
        assert!(result.column("revenue").is_none());
        assert!(result.column("qty").is_none());
    }

    #[test]
    fn groupby_agg_named_values() {
        let df = DataFrame::from_dict(
            &["g", "v"],
            vec![
                (
                    "g",
                    vec![
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("b".into()),
                    ],
                ),
                (
                    "v",
                    vec![
                        Scalar::Float64(10.0),
                        Scalar::Float64(20.0),
                        Scalar::Float64(30.0),
                    ],
                ),
            ],
        )
        .unwrap();

        let result = df
            .groupby(&["g"])
            .unwrap()
            .agg_named(&[("v_sum", "v", "sum"), ("v_count", "v", "count")])
            .unwrap();

        assert_eq!(result.index().len(), 2);

        // Verify actual aggregated values.
        let sums = result.column("v_sum").unwrap();
        let counts = result.column("v_count").unwrap();

        // Find which group index is "a" vs "b" (order may vary).
        let idx_a = result
            .index()
            .labels()
            .iter()
            .position(|l| matches!(l, IndexLabel::Utf8(s) if s == "a"))
            .expect("group 'a' must exist");
        let idx_b = result
            .index()
            .labels()
            .iter()
            .position(|l| matches!(l, IndexLabel::Utf8(s) if s == "b"))
            .expect("group 'b' must exist");

        // Group "a": sum(10+20)=30, count=2.
        assert_eq!(sums.values()[idx_a], Scalar::Float64(30.0));
        assert_eq!(counts.values()[idx_a], Scalar::Int64(2));

        // Group "b": sum(30)=30, count=1.
        assert_eq!(sums.values()[idx_b], Scalar::Float64(30.0));
        assert_eq!(counts.values()[idx_b], Scalar::Int64(1));
    }

